import{_ as e,o as r,c as n,ag as a}from"./chunks/framework.6MCaaFDc.js";const h=JSON.parse('{"title":"Programming Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"theory/programming/programming-concepts.md","filePath":"theory/programming/programming-concepts.md"}'),s={name:"theory/programming/programming-concepts.md"};function o(i,t,d,l,p,c){return r(),n("div",null,[...t[0]||(t[0]=[a(`<h1 id="programming-concepts" tabindex="-1">Programming Concepts <a class="header-anchor" href="#programming-concepts" aria-label="Permalink to &quot;Programming Concepts&quot;">​</a></h1><p>Before writing a single line of code, developers need to understand how software is built — the paradigms, tools, and processes that turn an idea into a working program. This page covers the theoretical foundations of programming.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10–11</p><p>Programming concepts (IDE, event-driven programming, development process) are introduced at Grade 10–11. OOP paradigm is Grade 11. Software engineering methodologies are Grade 12.</p></div><hr><h2 id="what-is-programming" tabindex="-1">What is Programming? <a class="header-anchor" href="#what-is-programming" aria-label="Permalink to &quot;What is Programming?&quot;">​</a></h2><p><strong>Programming</strong> (software development) is the process of creating instructions for a computer to follow.</p><p>A <strong>program</strong> is a set of instructions written in a programming language that a computer can execute to perform a specific task.</p><p><strong>Programming languages:</strong></p><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Low-level</strong></td><td>Close to machine code; fast but complex</td><td>Assembly, machine code</td></tr><tr><td><strong>Mid-level</strong></td><td>Balances control and readability</td><td>C, C++</td></tr><tr><td><strong>High-level</strong></td><td>Human-readable; most common</td><td>Delphi, Python, Java, JavaScript</td></tr><tr><td><strong>Very high-level</strong></td><td>Domain-specific</td><td>SQL, HTML</td></tr></tbody></table><hr><h2 id="the-development-process" tabindex="-1">The Development Process <a class="header-anchor" href="#the-development-process" aria-label="Permalink to &quot;The Development Process&quot;">​</a></h2><p>Software is not just written — it is designed, tested, and maintained.</p><h3 id="phases-of-software-development" tabindex="-1">Phases of Software Development: <a class="header-anchor" href="#phases-of-software-development" aria-label="Permalink to &quot;Phases of Software Development:&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Analysis        → Understand what the software must do</span></span>
<span class="line"><span>2. Design          → Plan algorithms, data structures, interface</span></span>
<span class="line"><span>3. Coding          → Write the source code</span></span>
<span class="line"><span>4. Testing         → Find and fix errors</span></span>
<span class="line"><span>5. Implementation  → Deploy the software to users</span></span>
<span class="line"><span>6. Maintenance     → Update, fix bugs, improve</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><hr><h2 id="ide-—-integrated-development-environment" tabindex="-1">IDE — Integrated Development Environment <a class="header-anchor" href="#ide-—-integrated-development-environment" aria-label="Permalink to &quot;IDE — Integrated Development Environment&quot;">​</a></h2><p>An <strong>IDE</strong> is a software application that provides tools for writing, testing, and debugging programs in one integrated environment.</p><p><strong>Components of an IDE:</strong></p><table tabindex="0"><thead><tr><th>Component</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Code editor</strong></td><td>Write source code with syntax highlighting and autocomplete</td></tr><tr><td><strong>Compiler/Interpreter</strong></td><td>Translates code to machine code or executes it</td></tr><tr><td><strong>Debugger</strong></td><td>Step through code; inspect variables; find errors</td></tr><tr><td><strong>Build tools</strong></td><td>Compile and link the project</td></tr><tr><td><strong>Form designer</strong></td><td>Drag-and-drop interface design (Delphi)</td></tr><tr><td><strong>Project manager</strong></td><td>Manage all files in the project</td></tr></tbody></table><p><strong>IDE Examples:</strong></p><table tabindex="0"><thead><tr><th>IDE</th><th>Language(s)</th><th>Use</th></tr></thead><tbody><tr><td>Delphi (RAD Studio)</td><td>Object Pascal</td><td>Windows applications</td></tr><tr><td>Visual Studio Code</td><td>Many (Python, JS, etc.)</td><td>General purpose</td></tr><tr><td>PyCharm</td><td>Python</td><td>Python development</td></tr><tr><td>IntelliJ IDEA</td><td>Java, Kotlin</td><td>Java development</td></tr><tr><td>Eclipse</td><td>Java, C++</td><td>Cross-platform</td></tr><tr><td>NetBeans</td><td>Java</td><td>Java development</td></tr></tbody></table><hr><h2 id="programming-paradigms" tabindex="-1">Programming Paradigms <a class="header-anchor" href="#programming-paradigms" aria-label="Permalink to &quot;Programming Paradigms&quot;">​</a></h2><p>A <strong>paradigm</strong> is a style or approach to programming.</p><table tabindex="0"><thead><tr><th>Paradigm</th><th>Description</th><th>Examples</th></tr></thead><tbody><tr><td><strong>Procedural</strong></td><td>Code executes step-by-step in procedures</td><td>Early BASIC, Pascal</td></tr><tr><td><strong>Event-driven</strong></td><td>Code responds to events (clicks, keystrokes)</td><td>Delphi, JavaScript</td></tr><tr><td><strong>Object-oriented (OOP)</strong></td><td>Code organised into objects with data and methods</td><td>Delphi, Java, Python, C++</td></tr><tr><td><strong>Functional</strong></td><td>Functions as first-class objects; no side effects</td><td>Haskell, Erlang, parts of JavaScript</td></tr><tr><td><strong>Declarative</strong></td><td>Specify what to achieve, not how</td><td>SQL, HTML</td></tr></tbody></table><hr><h2 id="event-driven-programming" tabindex="-1">Event-Driven Programming <a class="header-anchor" href="#event-driven-programming" aria-label="Permalink to &quot;Event-Driven Programming&quot;">​</a></h2><p><strong>Event-driven programming</strong> is a paradigm where the flow of the program is determined by events — user actions or system messages.</p><p><strong>Events:</strong></p><ul><li>Mouse click (<code>OnClick</code>)</li><li>Key press (<code>OnKeyPress</code>, <code>OnKeyDown</code>)</li><li>Form loading (<code>OnCreate</code>)</li><li>Text changed (<code>OnChange</code>)</li><li>Timer tick (<code>OnTimer</code>)</li></ul><p><strong>How it works in Delphi:</strong></p><ol><li>User places a button on a form</li><li>Delphi generates a blank event handler: <code>procedure TForm1.btnSubmitClick(Sender: TObject)</code></li><li>Developer writes code inside the handler</li><li>When the button is clicked, the code executes</li></ol><div class="language-pascal vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">pascal</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">procedure</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> TForm1.btnCalculateClick</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Sender: TObject);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">var</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  iNum1, iNum2, iTotal: </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Integer</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">begin</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  iNum1 := StrToInt(edtNum1.Text);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  iNum2 := StrToInt(edtNum2.Text);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  iTotal := iNum1 + iNum2;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  lblResult.Caption := </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Total: &#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> + IntToStr(iTotal);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">end</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>Advantages of event-driven programming:</strong></p><ul><li>Natural fit for GUI applications</li><li>Program responds to user — not fixed execution order</li><li>Easy to handle multiple input types simultaneously</li><li>Code is modular — each event handler is independent</li></ul><hr><h2 id="object-oriented-programming-oop" tabindex="-1">Object-Oriented Programming (OOP) <a class="header-anchor" href="#object-oriented-programming-oop" aria-label="Permalink to &quot;Object-Oriented Programming (OOP)&quot;">​</a></h2><p><strong>OOP</strong> organises code into <strong>objects</strong> — instances of <strong>classes</strong> that bundle data (attributes) and behaviour (methods) together.</p><div class="tip custom-block github-alert"><p class="custom-block-title">See Also</p><p>Full OOP coverage with Delphi examples is in <a href="./oop-principles.html">OOP Principles</a> and <a href="./../../practical/delphi/oop-delphi.html">OOP in Delphi</a>.</p></div><p><strong>Core OOP concepts:</strong></p><table tabindex="0"><thead><tr><th>Concept</th><th>Description</th></tr></thead><tbody><tr><td><strong>Class</strong></td><td>Blueprint/template for creating objects</td></tr><tr><td><strong>Object</strong></td><td>Instance of a class — actual usable entity</td></tr><tr><td><strong>Attribute</strong></td><td>Data stored in an object (property)</td></tr><tr><td><strong>Method</strong></td><td>Action an object can perform (procedure/function)</td></tr><tr><td><strong>Encapsulation</strong></td><td>Bundling data and methods; hiding internal details</td></tr><tr><td><strong>Inheritance</strong></td><td>Child class inherits attributes/methods from parent</td></tr><tr><td><strong>Polymorphism</strong></td><td>Same method name behaves differently in different classes</td></tr><tr><td><strong>Abstraction</strong></td><td>Hiding complexity; exposing only what is needed</td></tr></tbody></table><hr><h2 id="types-of-errors" tabindex="-1">Types of Errors <a class="header-anchor" href="#types-of-errors" aria-label="Permalink to &quot;Types of Errors&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Syntax error</strong></td><td>Violates language rules — code won&#39;t compile</td><td>Missing <code>end;</code>, wrong spelling</td></tr><tr><td><strong>Runtime error</strong></td><td>Valid syntax but fails during execution</td><td>Division by zero, file not found</td></tr><tr><td><strong>Logic error</strong></td><td>Code runs but gives wrong result</td><td>Using <code>+</code> instead of <code>*</code></td></tr></tbody></table><p><strong>Debugging</strong> is the process of finding and fixing errors.</p><p><strong>Debugging techniques:</strong></p><ul><li><strong>Tracing</strong> — reading through code step by step</li><li><strong>Breakpoints</strong> — pause execution at a specific line</li><li><strong>Watch variables</strong> — monitor variable values as code runs</li><li><strong>Desk checking</strong> — paper trace of algorithm</li></ul><hr><h2 id="compilers-and-interpreters" tabindex="-1">Compilers and Interpreters <a class="header-anchor" href="#compilers-and-interpreters" aria-label="Permalink to &quot;Compilers and Interpreters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th><strong>Compiler</strong></th><th><strong>Interpreter</strong></th></tr></thead><tbody><tr><td>Process</td><td>Translates entire source code to machine code before execution</td><td>Translates and executes one line at a time</td></tr><tr><td>Speed</td><td>Fast execution (compiled machine code)</td><td>Slower (translation on the fly)</td></tr><tr><td>Error detection</td><td>All errors shown before running</td><td>Stops at first error</td></tr><tr><td>Output</td><td>Executable file (.exe)</td><td>No standalone executable</td></tr><tr><td>Examples</td><td>Delphi, C, C++</td><td>Python, JavaScript (traditionally)</td></tr></tbody></table><p><strong>Delphi uses a compiler</strong> — source code is compiled to a <code>.exe</code> before running.</p><hr><h2 id="source-code-object-code-and-machine-code" tabindex="-1">Source Code, Object Code, and Machine Code <a class="header-anchor" href="#source-code-object-code-and-machine-code" aria-label="Permalink to &quot;Source Code, Object Code, and Machine Code&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Source code (.pas)</span></span>
<span class="line"><span>    ↓ Compiler</span></span>
<span class="line"><span>Object code (binary)</span></span>
<span class="line"><span>    ↓ Linker (combines libraries)</span></span>
<span class="line"><span>Executable (.exe)</span></span>
<span class="line"><span>    ↓ CPU executes</span></span>
<span class="line"><span>Machine code (0s and 1s)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><table tabindex="0"><thead><tr><th>Code Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Source code</strong></td><td>Human-readable code written by programmer</td></tr><tr><td><strong>Object code</strong></td><td>Intermediate binary from compiler — not yet executable</td></tr><tr><td><strong>Machine code</strong></td><td>Binary instructions executed directly by CPU</td></tr><tr><td><strong>Bytecode</strong></td><td>Intermediate code (Java .class files) — run by a virtual machine</td></tr></tbody></table><hr><h2 id="software-testing" tabindex="-1">Software Testing <a class="header-anchor" href="#software-testing" aria-label="Permalink to &quot;Software Testing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Testing Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Unit testing</strong></td><td>Testing individual procedures/functions in isolation</td></tr><tr><td><strong>Integration testing</strong></td><td>Testing how components work together</td></tr><tr><td><strong>System testing</strong></td><td>Testing the complete system</td></tr><tr><td><strong>User acceptance testing (UAT)</strong></td><td>End users verify the software meets requirements</td></tr><tr><td><strong>Regression testing</strong></td><td>After fixing a bug, check it didn&#39;t break other things</td></tr></tbody></table><p><strong>Test data types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Purpose</th><th>Example</th></tr></thead><tbody><tr><td><strong>Normal data</strong></td><td>Typical valid input</td><td>Mark: 75</td></tr><tr><td><strong>Boundary data</strong></td><td>Values at the edge of valid range</td><td>Mark: 0, Mark: 100</td></tr><tr><td><strong>Erroneous data</strong></td><td>Invalid input that should be rejected</td><td>Mark: -5, Mark: &quot;abc&quot;</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Program</strong></td><td>Set of instructions for a computer to execute</td></tr><tr><td><strong>IDE</strong></td><td>Integrated Development Environment — coding tool with editor, compiler, debugger</td></tr><tr><td><strong>Compiler</strong></td><td>Translates entire source code to machine code</td></tr><tr><td><strong>Interpreter</strong></td><td>Translates and executes source code one line at a time</td></tr><tr><td><strong>Paradigm</strong></td><td>Style of programming (procedural, OOP, event-driven)</td></tr><tr><td><strong>Event-driven</strong></td><td>Program flow controlled by user/system events</td></tr><tr><td><strong>Debugging</strong></td><td>Finding and fixing errors in code</td></tr><tr><td><strong>Syntax error</strong></td><td>Violation of language rules — code won&#39;t compile</td></tr><tr><td><strong>Runtime error</strong></td><td>Error occurring during execution</td></tr><tr><td><strong>Logic error</strong></td><td>Code runs but produces incorrect results</td></tr><tr><td><strong>OOP</strong></td><td>Object-Oriented Programming</td></tr><tr><td><strong>Source code</strong></td><td>Human-readable program code</td></tr><tr><td><strong>Machine code</strong></td><td>Binary instructions executed by the CPU</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is an IDE? Give THREE components of an IDE.&quot;</strong> — Integrated Development Environment; components: code editor, compiler, debugger, form designer, project manager</p></li><li><p><strong>&quot;What is event-driven programming? Give TWO examples of events in Delphi.&quot;</strong> — Program flow determined by user/system events; examples: OnClick (button click), OnCreate (form load), OnChange (text field change), OnTimer (timer tick)</p></li><li><p><strong>&quot;What is the difference between a compiler and an interpreter?&quot;</strong> — Compiler translates entire program before execution → fast .exe file; Interpreter translates one line at a time → slower, no separate file</p></li><li><p><strong>&quot;Explain the difference between a syntax error, runtime error, and logic error&quot;</strong> — Syntax: violates language rules (won&#39;t compile); Runtime: valid syntax but fails during execution (divide by zero); Logic: runs but gives wrong result (wrong formula)</p></li><li><p><strong>&quot;Name THREE phases of software development&quot;</strong> — analysis; design; coding; testing; implementation; maintenance</p></li></ol></div>`,66)])])}const m=e(s,[["render",o]]);export{h as __pageData,m as default};
